const dashboard=ref<any>({}),rows=ref<any[]>([]),search=ref(''),dialog=ref(false),newWorker=ref<any>({}),editingWorker=ref(false)
const companyDialog=ref(false),newCompany=ref<any>({}),editingCompany=ref(false),adminDialog=ref(false),adminForm=ref<any>({}),editingAdmin=ref(false)
