const unitDialog=ref(false),unitForm=ref<any>({}),editingUnit=ref(false),areaDialog=ref(false),areaForm=ref<any>({}),editingArea=ref(false),teamDialog=ref(false),teamForm=ref<any>({}),editingTeam=ref(false),projectUnits=ref<any[]>([]),projectTeams=ref<any[]>([])
const roleDialog=ref(false),roleForm=ref<any>({}),editingRole=ref(false),projectUserDialog=ref(false),projectUserForm=ref<any>({}),editingProjectUser=ref(false),scopeRoles=ref<any[]>([])
const importDialog=ref(false),importRows=ref<any[]>([]),importPreview=ref<any>({validCount:0,errorCount:0})
const courseDialog=ref(false),courseForm=ref<any>({}),editingCourse=ref(false),questionDialog=ref(false),questionForm=ref<any>({}),editingQuestion=ref(false),questionBank=ref<any[]>([])
const ledgerDialog=ref(false),ledgerForm=ref<any>({passed:true}),educationCourses=ref<any[]>([]),projectWorkers=ref<any[]>([]),selectedCourseId=ref<any>(null)
