const attendanceStats=ref<any>({})
const companyFilter=ref<any>(null)
const scopeDialog=ref(false),scopeOptions=ref<any>({companies:[],projects:[]}),scope=ref<any>(session.context)
const canManageCompany=computed(()=>session.role==='SUPER_ADMIN'||session.role==='COMPANY_ADMIN'||(session.companyModules[String(scope.value.companyId||scope.value.id)]||[]).includes('*')||(session.projectModules[String(scope.value.id)]||[]).includes('*'))
const expanded=ref<string[]>(['platformManage','projectManage','companySummary','projectPermission','baseManage','realnameManage','educationManage','accessManage','attendanceManage','reportManage'])
const platformMenus:any[]=[
 {key:'platformDashboard',label:'平台工作台',icon:DataBoard},
 {key:'platformManage',label:'平台管理',icon:Setting,children:[['companies','企业管理',OfficeBuilding],['platformUsers','管理账号',User],['workTypes','工种字典',Setting]]}
]
const companyMenus:any[]=[{key:'companyDashboard',label:'企业工作台',icon:DataBoard},{key:'projectManage',label:'项目管理',icon:OfficeBuilding,children:[['projectHealth','项目健康度',DataBoard],['projects','项目列表',OfficeBuilding],['companyUsers','用户管理',User],['companyRoles','角色管理',Setting]]},{key:'companySummary',label:'企业汇总',icon:Calendar,children:[['companyWorkers','人员汇总',User],['companyAttendance','考勤汇总',Calendar]]}]
const projectMenus:any[]=[{key:'dashboard',label:'项目工作台',icon:DataBoard},{key:'projectPermission',label:'用户与权限',icon:Setting,children:[['projectUsers','用户管理',User],['projectRoles','角色管理',Setting]]},{key:'baseManage',label:'项目基础',icon:Location,children:[['units','参建单位',OfficeBuilding],['areas','项目区域',Location],['teams','班组管理',User]]},{key:'realnameManage',label:'实名制管理',icon:User,children:[['workers','劳务工人',User],['blacklists','黑名单管理',Key]]},{key:'educationManage',label:'安全教育',icon:Reading,children:[['courses','教育课程',Reading],['questions','考题管理',Reading],['trainingTasks','培训任务',Promotion],['exams','考试记录',Reading],['ledger','安全教育台账',Reading]]},{key:'accessManage',label:'设备与门禁',icon:Key,children:[['devices','考勤设备',Monitor],['permissions','区域权限',Key],['syncLogs','下发记录',Promotion],['mockDevice','模拟设备',Connection]]},{key:'attendanceManage',label:'考勤管理',icon:Calendar,children:[['attendance','考勤记录',Calendar],['abnormal','异常考勤',Calendar],['attendanceStat','考勤统计',DataBoard]]},{key:'reportManage',label:'数据上报',icon:Promotion,children:[['workerReports','人员上报',Promotion],['attendanceReports','考勤上报',Promotion],['reportLogs','上报日志',Promotion]]},{key:'screen',label:'项目大屏',icon:FullScreen}]
function allowedMenus(list:any[],modules:string[]){if(session.role!=='COMPANY_USER'||modules.includes('*'))return list;return list.filter(g=>modules.includes(g.key)).map(g=>g.children?{...g,children:g.children}:g)}
const menus=computed(()=>scope.value.type==='platform'?platformMenus:scope.value.type==='company'?allowedMenus(companyMenus,session.companyModules[String(scope.value.id)]||[]):allowedMenus(projectMenus,session.projectModules[String(scope.value.id)]||[]))
const menuItems=computed(()=>menus.value.flatMap((g:any)=>g.children?g.children.map((i:any)=>({key:i[0],label:i[1],icon:i[2]})):[g]))
const title=computed(()=>menuItems.value.find((x:any)=>x.key===active.value)?.label||'工作台')
const scopeTypeName=computed(()=>scope.value.type==='platform'?'平台级':scope.value.type==='company'?'企业级':'项目级')
const filtered=computed(()=>rows.value.filter(r=>!search.value||JSON.stringify(r).includes(search.value)))
const map:any={companies:'/companies',platformUsers:'/platform-users',workTypes:'/work-types',companyUsers:'/company-users',companyRoles:'/company-roles',projectUsers:'/project-users',projectRoles:'/project-roles',projects:'/projects',units:'/participant-units',areas:'/project-areas',teams:'/teams',workers:'/workers',blacklists:'/workers',courses:'/education/courses',questions:'/education/questions',trainingTasks:'/education/training-tasks',exams:'/education/exams',ledger:'/education/ledger',devices:'/devices',permissions:'/worker-area-permissions',syncLogs:'/device-sync-logs',attendance:'/attendance/records',abnormal:'/attendance/abnormal',reportLogs:'/gov/submit/logs'}
const tags:any={ACTIVE:['正常','success'],DISABLED:['禁用','danger'],ON_SITE:['在场','success'],LEFT_SITE:['已退场','info'],WAIT_ENTRY:['待入场','warning'],BLACKLIST:['黑名单','danger'],PASSED:['已通过','success'],NOT_STARTED:['未开始','warning'],ACCESS_ENABLED:['允许进出','success'],ACCESS_DISABLED:['禁止进出','danger'],ONLINE:['在线','success'],OFFLINE:['离线','danger'],ALLOW:['允许','success'],DENY:['拒绝','danger'],SUCCESS:['成功','success'],FAILED:['失败','danger'],SYNCED:['已下发','success'],NOT_SYNCED:['未下发','info'],PENDING_SYNC:['待下发','warning'],NOT_SUBMITTED:['未上报','info']}
const companyModuleOptions=[['companyDashboard','企业工作台'],['projectManage','项目管理'],['companySummary','企业汇总']]
const projectModuleOptions=[['dashboard','项目工作台'],['projectPermission','用户与权限'],['baseManage','项目基础'],['realnameManage','实名制管理'],['educationManage','安全教育'],['accessManage','设备与门禁'],['attendanceManage','考勤管理'],['reportManage','数据上报'],['screen','项目大屏']]
const roleModuleOptions=computed(()=>active.value==='companyRoles'?companyModuleOptions:projectModuleOptions)
function tag(v:string){return tags[v]||[v||'-','info']}
function questionOptions(options:string){return (options||'').replace(/\s+(?=[A-ZＡ-Ｚ][.、．])/gi,'；').split(/[；;\n]/).map(x=>x.trim()).filter(Boolean)}
function formatDateTime(v:string){return v?String(v).replace('T',' ').slice(0,19):'-'}
async function login(){loading.value=true;try{const d:any=await post('/auth/login',loginForm.value);session.login(d);logged.value=true;await loadScopeOptions();if(d.role==='SUPER_ADMIN')await select('platformDashboard');else{const c=scopeOptions.value.companies[0];chooseScope('company',c)}ElMessage.success('欢迎进入 BuildGuard')}catch(e:any){ElMessage.error(e.message)}finally{loading.value=false}}
async function select(k:string){active.value=k;search.value='';if(k==='screen'&&scope.value.type==='project'){window.open(`${import.meta.env.BASE_URL}screen/project/${scope.value.id}`,'_blank','noopener,noreferrer');return}if(k==='platformDashboard'){dashboard.value=await get('/platform/overview');return}if(k==='companyDashboard'){[dashboard.value,dashboardProjects.value,dashboardHealth.value]=await Promise.all([get(`/company-dashboard/overview?companyId=${scope.value.id}`),get(`/company-dashboard/projects?companyId=${scope.value.id}`),get(`/company-dashboard/project-health?companyId=${scope.value.id}`)]);return}if(k==='projectHealth'){rows.value=await get(`/company-dashboard/project-health?companyId=${scope.value.id}`);return}if(k==='dashboard'){await loadDashboard();return}if(k==='attendanceStat'){await loadAttendanceStats();return}if(['companyWorkers','companyAttendance'].includes(k)){rows.value=[];return}if(k==='teams')projectUnits.value=await get(`/participant-units?projectId=${scope.value.id}`);if(k==='companyUsers')scopeRoles.value=await get(`/company-roles?companyId=${scope.value.id}`);if(k==='projectUsers')scopeRoles.value=await get(`/project-roles?projectId=${scope.value.id}`);if(k==='questions'){rows.value=await get(`/education/questions?projectId=${scope.value.id}`);return}if(k==='permissions'){[projectWorkers.value,projectAreas.value,rows.value]=await Promise.all([get(`/workers?projectId=${scope.value.id}`),get(`/project-areas?projectId=${scope.value.id}`),get(`/worker-area-permissions?projectId=${scope.value.id}`)]);return}if(k==='trainingTasks')[educationCourses.value,projectWorkers.value,projectTeams.value]=await Promise.all([get(`/education/courses?projectId=${scope.value.id}`),get(`/workers?projectId=${scope.value.id}`),get(`/teams?projectId=${scope.value.id}`)]);if(k==='devices')projectAreas.value=await get(`/project-areas?projectId=${scope.value.id}`);if(map[k]){let url=map[k];if(k==='platformUsers'&&companyFilter.value)url+=`?companyId=${companyFilter.value}`;if(['companyUsers','companyRoles'].includes(k))url+=`?companyId=${scope.value.id}`;if(scope.value.type==='project'&&k!=='companies')url+=`${url.includes('?')?'&':'?'}projectId=${scope.value.id}`;if(k==='blacklists')url+=`&status=BLACKLIST`;if(scope.value.type==='company'&&k==='projects')url+=`?companyId=${scope.value.id}`;rows.value=await get(url)}else rows.value=[]}
async function loadDashboard(){dashboard.value=await get(`/project-dashboard/overview?projectId=${scope.value.id}`);rows.value=await get(`/attendance/records?projectId=${scope.value.id}`);await nextTick();drawCharts()}
async function loadAttendanceStats(){attendanceStats.value=await get(`/attendance/stat?projectId=${scope.value.id}`)}
async function loadScopeOptions(){scopeOptions.value=await get('/context/options')}
function toggleMenu(key:string){expanded.value=expanded.value.includes(key)?expanded.value.filter(x=>x!==key):[...expanded.value,key]}
function chooseScope(type:string,item?:any){if(type==='platform')scope.value={type:'platform',id:null,companyId:null,name:'平台级'};else if(type==='company')scope.value={type,id:item.id,companyId:item.id,name:item.name};else scope.value={type,id:item.id,companyId:item.companyId,name:item.projectName,companyName:scopeOptions.value.companies.find((c:any)=>c.id===item.companyId)?.name};session.setContext(scope.value);scopeDialog.value=false;select(type==='platform'?'platformDashboard':type==='company'?'companyDashboard':'dashboard');ElMessage.success(`已切换至${scope.value.name}`)}
function enterProject(r:any){const p=scopeOptions.value.projects.find((x:any)=>x.id===(r.projectId||r.id));chooseScope('project',p)}
function backCompany(){const c=scopeOptions.value.companies.find((x:any)=>x.id===scope.value.companyId);chooseScope('company',c)}
function drawCharts(){const trendEl=document.getElementById('trend'),pieEl=document.getElementById('pie');if(!trendEl||!pieEl)return;const days=Array.from({length:7},(_,i)=>{const d=new Date();d.setDate(d.getDate()-6+i);return d.toISOString().slice(0,10)}),counts=days.map(day=>new Set(rows.value.filter((r:any)=>String(r.attendanceTime||'').startsWith(day)).map((r:any)=>r.workerId)).size);const trend=echarts.getInstanceByDom(trendEl)||echarts.init(trendEl);trend.setOption({grid:{left:35,right:15,top:25,bottom:25},tooltip:{trigger:'axis'},xAxis:{type:'category',data:days.map(x=>x.slice(5))},yAxis:{type:'value',splitLine:{lineStyle:{color:'#edf2f7'}}},series:[{type:'line',smooth:true,data:counts,areaStyle:{color:'rgba(36,126,255,.12)'},lineStyle:{color:'#247eff',width:3},itemStyle:{color:'#247eff'}}]});const pie=echarts.getInstanceByDom(pieEl)||echarts.init(pieEl),data=(dashboard.value.workTypeStats||[]).map((x:any)=>({name:x.name,value:x.count}));pie.setOption(data.length?{tooltip:{trigger:'item'},legend:{bottom:0,type:'scroll'},series:[{type:'pie',radius:['42%','68%'],center:['50%','45%'],label:{formatter:'{b}\n{c}人'},data}]}:{title:{text:'暂无工种数据',left:'center',top:'42%',textStyle:{color:'#94a1ac',fontSize:13,fontWeight:'normal'}},series:[]})}
async function act(url:string,msg:string,data:unknown={}){try{await post(url,data);ElMessage.success(msg);await select(active.value)}catch(e:any){ElMessage.error(e.message)}}
async function syncWorker(r:any){await act(`/workers/${r.id}/sync-access`,'设备权限下发完成')}
async function mockCard(){newWorker.value={...newWorker.value,...await post('/id-card/mock-read')};ElMessage.success('身份证读取成功')}
async function openWorker(row?:any){editingWorker.value=!!row;newWorker.value=row?{...row}:{projectId:scope.value.id,status:'WAIT_ENTRY',workerType:'劳务工人'};[projectUnits.value,projectTeams.value,workTypeOptions.value]=await Promise.all([get(`/participant-units?projectId=${scope.value.id}`),get(`/teams?projectId=${scope.value.id}`),get('/work-types')]);dialog.value=true}
async function saveWorker(){try{if(editingWorker.value)await put(`/workers/${newWorker.value.id}`,newWorker.value);else await post('/workers',{...newWorker.value,projectId:scope.value.id});dialog.value=false;ElMessage.success(editingWorker.value?'人员档案已更新':'人员档案已创建');await select('workers')}catch(e:any){ElMessage.error(e.message)}}
async function deleteWorker(row:any){try{await ElMessageBox.confirm(`确定删除人员“${row.name}”吗？该人员关联的教育、区域权限、考勤和设备下发记录将一并删除，且不可恢复。`,'删除人员',{type:'warning'});await del(`/workers/${row.id}`);await select('workers');ElMessage.success('人员及其关联记录已删除')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
async function workerAction(row:any,type:string){const messages:any={entry:'人员已入场',exit:'人员已退场',blacklist:'人员已加入黑名单'};await act(`/workers/${row.id}/${type}`,messages[type])}
async function removeBlacklist(row:any){await act(`/workers/${row.id}/remove-blacklist`,'人员已移出黑名单')}
async function submitWorkerRealName(row:any){await act(`/workers/${row.id}/submit-realname`,'实名制信息模拟上报完成')}
async function toggleTeamLeader(row:any,enabled:boolean){try{let password='';if(enabled){const result:any=await ElMessageBox.prompt('请设置班组长 H5 登录密码','启用班组长权限',{inputType:'password',inputPlaceholder:'默认 123456',confirmButtonText:'启用',cancelButtonText:'取消'});password=result.value||'123456'}await post(`/workers/${row.id}/team-leader`,{enabled,password});await select('workers');ElMessage.success(enabled?'班组长 H5 权限已启用':'班组长 H5 权限已关闭')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
async function workerMore(command:string,row:any){if(command==='entry'||command==='exit'||command==='blacklist')return workerAction(row,command);if(command==='permission')return openPermission(row);if(command==='sync')return syncWorker(row);if(command==='report')return submitWorkerRealName(row);if(command==='delete')return deleteWorker(row)}
async function showWorkerDetail(row:any){workerDetail.value=await get(`/workers/${row.id}/detail`);workerDetailTab.value='basic';workerDetailDrawer.value=true}
function readWorkerPhoto(event:any,field:string){const file=event.target.files?.[0];event.target.value='';if(!file)return;if(file.size>2*1024*1024)return ElMessage.warning('图片请控制在 2MB 以内');const reader=new FileReader();reader.onload=()=>newWorker.value[field]=reader.result;reader.readAsDataURL(file)}
function readH5Photo(event:any,field:string){const file=event.target.files?.[0];event.target.value='';if(!file)return Promise.resolve(false);if(file.size>2*1024*1024){ElMessage.warning('图片请控制在 2MB 以内');return Promise.resolve(false)}return new Promise<boolean>((resolve,reject)=>{const reader=new FileReader();reader.onload=()=>{h5Worker.value[field]=reader.result;resolve(true)};reader.onerror=()=>reject(new Error('图片读取失败，请重新拍摄'));reader.readAsDataURL(file)})}
async function h5Login(){try{const r:any=await post('/h5/worker-entry/login',h5LoginForm.value);localStorage.setItem('token',r.token);h5User.value=r;h5Logged.value=true;h5Options.value=await get('/h5/worker-entry/options');const project=h5Options.value.projects[0],team=h5Options.value.teams.find((t:any)=>t.projectId===project?.id);h5Worker.value={projectId:project?.id,teamId:team?.id,workType:team?.workType};}catch(e:any){ElMessage.error(e.message)}}
async function h5Ocr(event:any){try{if(!await readH5Photo(event,'idCardPhotoUrl'))return;h5Worker.value={...h5Worker.value,...await post('/h5/worker-entry/id-card-ocr')};ElMessage.success('身份证照片模拟识别完成，请核对信息')}catch(e:any){ElMessage.error(e.message)}}
function h5ProjectChanged(){const team=h5Options.value.teams.find((t:any)=>t.projectId===h5Worker.value.projectId);h5Worker.value.teamId=team?.id;h5Worker.value.workType=team?.workType}
function resetH5Worker(){h5Worker.value={projectId:h5Worker.value.projectId,teamId:h5Worker.value.teamId,workType:h5Worker.value.workType}}
async function h5Submit(){try{const result:any=await post('/h5/worker-entry/workers',h5Worker.value);ElMessage.success(`人员保存成功。${result.syncMessage}`);resetH5Worker()}catch(e:any){ElMessage.error(e.message)}}
function exportWorkers(){const headers=['人员编号','姓名','身份证号','手机号','性别','民族','工种','参建单位','班组','人员状态','入场日期','退场日期','安全教育','门禁状态','实名制上报'];const body=filtered.value.map((w:any)=>[w.personCode,w.name,w.idCardNo,w.phone,w.gender,w.nation,w.workType,unitName(w.participantUnitId),teamName(w.teamId),tag(w.status)[0],w.entryDate,w.exitDate,tag(w.safetyEducationStatus)[0],tag(w.accessStatus)[0],tag(w.realNameReportStatus)[0]].map(x=>`"${String(x||'').replace(/"/g,'""')}"`).join(','));const url=URL.createObjectURL(new Blob(['\uFEFF'+[headers.join(','),...body].join('\n')],{type:'text/csv;charset=utf-8'}));const a=document.createElement('a');a.href=url;a.download='劳务工人实名制档案.csv';a.click();URL.revokeObjectURL(url)}
async function showQr(row:any){const r:any=await post(`/workers/${row.id}/generate-qrcode`);await ElMessageBox.alert(r.url,'人员二维码内容',{confirmButtonText:'关闭'})}
async function openPermission(worker?:any){[projectWorkers.value,projectAreas.value]=await Promise.all([get(`/workers?projectId=${scope.value.id}`),get(`/project-areas?projectId=${scope.value.id}`)]);const selected=worker||projectWorkers.value[0];if(!selected)return ElMessage.warning('请先创建劳务工人');const existing:any[]=await get(`/worker-area-permissions?projectId=${scope.value.id}`);permissionForm.value={workerId:selected.id,areaIds:existing.filter(p=>p.workerId===selected.id&&p.permissionStatus==='ACTIVE').map(p=>p.areaId)};permissionDialog.value=true}
async function savePermission(){try{await post('/worker-area-permissions/save',permissionForm.value);permissionDialog.value=false;await select('permissions');ElMessage.success('区域权限已保存，等待下发设备')}catch(e:any){ElMessage.error(e.message)}}
function permissionAreas(workerId:number){const ids=rows.value.filter(p=>p.workerId===workerId&&p.permissionStatus==='ACTIVE').map(p=>p.areaId);return projectAreas.value.filter(a=>ids.includes(a.id)).map(a=>a.areaName).join('、')||'未配置'}
async function downloadImportTemplate(){const csv:any=await get('/workers/import-template');const url=URL.createObjectURL(new Blob([csv],{type:'text/csv;charset=utf-8'}));const a=document.createElement('a');a.href=url;a.download='劳务工人批量导入模板.csv';a.click();URL.revokeObjectURL(url)}
function parseCsvLine(line:string){const cells:string[]=[];let cell='',quoted=false;for(let i=0;i<line.length;i++){const c=line[i];if(c==='"'&&line[i+1]==='"'){cell+='"';i++}else if(c==='"')quoted=!quoted;else if(c===','&&!quoted){cells.push(cell.trim());cell=''}else cell+=c}cells.push(cell.trim());return cells}
async function chooseImportFile(event:any){const file=event.target.files?.[0];event.target.value='';if(!file)return;const lines=(await file.text()).replace(/^\uFEFF/,'').split(/\r?\n/).filter((x:string)=>x.trim());const headers=parseCsvLine(lines.shift()||'');const keys:any={'姓名':'name','身份证号':'idCardNo','手机号':'phone','工种':'workType','参建单位名称':'participantUnitName','班组名称':'teamName','入场日期':'entryDate','允许进入区域':'allowedAreas'};const parsed=lines.map((line:string)=>Object.fromEntries(parseCsvLine(line).map((v,i)=>[keys[headers[i]]||headers[i],v])));try{importPreview.value=await post('/workers/import-preview',{projectId:scope.value.id,rows:parsed});importRows.value=importPreview.value.rows;importDialog.value=true}catch(e:any){ElMessage.error(e.message)}}
async function confirmImport(){try{const r:any=await post('/workers/import-confirm',{projectId:scope.value.id,rows:importRows.value});importDialog.value=false;ElMessage.success(`成功导入 ${r.count} 名人员`);await select('workers')}catch(e:any){ElMessage.error(e.message)}}
function openCompany(row?:any){editingCompany.value=!!row;newCompany.value=row?{...row}:{};companyDialog.value=true}
async function saveCompany(){if(editingCompany.value)await put(`/companies/${newCompany.value.id}`,newCompany.value);else await post('/companies',{...newCompany.value,status:'ACTIVE'});companyDialog.value=false;newCompany.value={};await loadScopeOptions();await select('companies');ElMessage.success(editingCompany.value?'企业信息已更新':'企业创建成功')}
async function deleteCompany(row:any){try{await ElMessageBox.confirm(`确定删除企业“${row.name}”吗？`,'删除企业',{confirmButtonText:'删除',cancelButtonText:'取消',type:'warning'});await del(`/companies/${row.id}`);await loadScopeOptions();await select('companies');ElMessage.success('企业已删除')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
function openWorkType(row?:any){editingWorkType.value=!!row;workTypeForm.value=row?{...row}:{status:'ACTIVE',sortOrder:0};workTypeDialog.value=true}
async function saveWorkType(){try{if(editingWorkType.value)await put(`/work-types/${workTypeForm.value.id}`,workTypeForm.value);else await post('/work-types',workTypeForm.value);workTypeDialog.value=false;await select('workTypes');ElMessage.success(editingWorkType.value?'工种已更新':'工种已创建')}catch(e:any){ElMessage.error(e.message)}}
async function deleteWorkType(row:any){try{await ElMessageBox.confirm(`确定删除工种“${row.name}”吗？`,'删除工种',{type:'warning'});await del(`/work-types/${row.id}`);await select('workTypes');ElMessage.success('工种已删除')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
function openProject(row?:any){editingProject.value=!!row;projectForm.value=row?{...row}:{companyId:scope.value.id,status:'筹备中'};projectDialog.value=true}
async function saveProject(){if(editingProject.value)await put(`/projects/${projectForm.value.id}`,projectForm.value);else await post('/projects',projectForm.value);projectDialog.value=false;await loadScopeOptions();await select('projects');ElMessage.success(editingProject.value?'项目已更新':'项目已创建')}
async function deleteProject(row:any){try{await ElMessageBox.confirm(`确定删除项目“${row.projectName}”吗？`,'删除项目',{type:'warning'});await del(`/projects/${row.id}`);await loadScopeOptions();await select('projects');ElMessage.success('项目已删除')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
function openCompanyUser(row?:any){editingCompanyUser.value=!!row;companyUserForm.value=row?{id:row.id,name:row.name,phone:row.phone,role:row.role,status:['ACTIVE','DISABLED'].includes(row.status)?row.status:'ACTIVE',companyRoleIds:[...(row.companyRoleIds||[])],projectIds:(row.projectIds||[]).filter((id:number)=>scopeOptions.value.projects.some((p:any)=>p.id===id&&p.companyId===scope.value.id)),allProjects:(row.allProjectCompanyIds||[]).includes(scope.value.id)}:{companyIds:[scope.value.id],companyRoleIds:[],allProjectCompanyIds:[scope.value.id],projectIds:[],allProjects:true,status:'ACTIVE'};companyUserDialog.value=true}
async function saveCompanyUser(){const f={...companyUserForm.value,companyIds:[scope.value.id],allProjectCompanyIds:companyUserForm.value.allProjects?[scope.value.id]:[],projectIds:companyUserForm.value.allProjects?[]:(companyUserForm.value.projectIds||[])};if(editingCompanyUser.value)await put(`/company-users/${f.id}`,f);else await post('/company-users',f);companyUserDialog.value=false;await select('companyUsers');ElMessage.success(editingCompanyUser.value?'用户已更新':'用户已创建')}
async function deleteCompanyUser(row:any){try{await ElMessageBox.confirm(`确定删除用户“${row.name}”吗？`,'删除用户',{type:'warning'});await del(`/company-users/${row.id}`);await select('companyUsers');ElMessage.success('用户已删除')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
function openRole(row?:any){editingRole.value=!!row;roleForm.value=row?{...row,moduleKeys:[...(row.moduleKeys||[])]}:{scopeId:scope.value.id,status:'ACTIVE',moduleKeys:[]};roleDialog.value=true}
async function saveRole(){const base=active.value==='companyRoles'?'/company-roles':'/project-roles';if(editingRole.value)await put(`${base}/${roleForm.value.id}`,roleForm.value);else await post(base,roleForm.value);roleDialog.value=false;await select(active.value);ElMessage.success(editingRole.value?'角色已更新':'角色已创建')}
async function deleteRole(row:any){try{await ElMessageBox.confirm(`确定删除角色“${row.name}”吗？`,'删除角色',{type:'warning'});await del(`/${active.value==='companyRoles'?'company-roles':'project-roles'}/${row.id}`);await select(active.value);ElMessage.success('角色已删除')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
function openProjectUser(row?:any){editingProjectUser.value=!!row;projectUserForm.value=row?{id:row.id,name:row.name,phone:row.phone,status:row.status,projectIds:[scope.value.id],projectRoleIds:[...(row.projectRoleIds||[])]}:{projectIds:[scope.value.id],projectRoleIds:[],status:'ACTIVE'};projectUserDialog.value=true}
async function saveProjectUser(){if(editingProjectUser.value)await put(`/project-users/${projectUserForm.value.id}`,projectUserForm.value);else await post('/project-users',projectUserForm.value);projectUserDialog.value=false;await select('projectUsers');ElMessage.success(editingProjectUser.value?'项目用户已更新':'项目用户已创建')}
async function deleteProjectUser(row:any){try{await ElMessageBox.confirm(`确定从当前项目移除用户“${row.name}”吗？`,'移除项目用户',{type:'warning'});await del(`/project-users/${row.id}?projectId=${scope.value.id}`);await select('projectUsers');ElMessage.success('项目用户已移除')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
async function resetCompanyUser(row:any){const r:any=await post(`/company-users/${row.id}/reset-password`);await ElMessageBox.alert(`临时密码：${r.temporaryPassword}`,'密码重置成功')}
function openUnit(row?:any){editingUnit.value=!!row;unitForm.value=row?{...row}:{projectId:scope.value.id,status:'ACTIVE'};unitDialog.value=true}
async function saveUnit(){if(editingUnit.value)await put(`/participant-units/${unitForm.value.id}`,unitForm.value);else await post('/participant-units',unitForm.value);unitDialog.value=false;await select('units');ElMessage.success(editingUnit.value?'参建单位已更新':'参建单位已创建')}
async function deleteUnit(row:any){try{await ElMessageBox.confirm(`确定删除参建单位“${row.unitName}”吗？`,'删除参建单位',{type:'warning'});await del(`/participant-units/${row.id}`);await select('units');ElMessage.success('参建单位已删除')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
function openArea(row?:any){editingArea.value=!!row;areaForm.value=row?{...row}:{projectId:scope.value.id,status:'ACTIVE',isControlled:false,requireSafetyEducation:true,isDangerArea:false};areaDialog.value=true}
async function saveArea(){if(editingArea.value)await put(`/project-areas/${areaForm.value.id}`,areaForm.value);else await post('/project-areas',areaForm.value);areaDialog.value=false;await select('areas');ElMessage.success(editingArea.value?'项目区域已更新':'项目区域已创建')}
async function deleteArea(row:any){try{await ElMessageBox.confirm(`确定删除区域“${row.areaName}”吗？`,'删除区域',{type:'warning'});await del(`/project-areas/${row.id}`);await select('areas');ElMessage.success('项目区域已删除')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
function openTeam(row?:any){editingTeam.value=!!row;teamForm.value=row?{...row}:{projectId:scope.value.id,status:'ACTIVE'};teamDialog.value=true}
async function saveTeam(){if(editingTeam.value)await put(`/teams/${teamForm.value.id}`,teamForm.value);else await post('/teams',teamForm.value);teamDialog.value=false;await select('teams');ElMessage.success(editingTeam.value?'班组已更新':'班组已创建')}
async function deleteTeam(row:any){try{await ElMessageBox.confirm(`确定删除班组“${row.teamName}”吗？`,'删除班组',{type:'warning'});await del(`/teams/${row.id}`);await select('teams');ElMessage.success('班组已删除')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
function unitName(id:number){return projectUnits.value.find((u:any)=>u.id===id)?.unitName||'-'}
function teamName(id:number){return projectTeams.value.find((t:any)=>t.id===id)?.teamName||'-'}
function constructionUnits(){return projectUnits.value.filter((u:any)=>['总包单位','劳务分包','专业分包','设备分包','其他施工类参建单位'].includes(u.unitType))}
function openAdmin(row?:any){editingAdmin.value=!!row;adminForm.value=row?{...row,companyIds:[...(row.companyIds||[])]}:{role:'COMPANY_ADMIN',companyIds:[],status:'ACTIVE'};adminDialog.value=true}
async function saveAdmin(){if(editingAdmin.value)await put(`/platform-users/${adminForm.value.id}`,adminForm.value);else await post('/platform-users',adminForm.value);adminDialog.value=false;await select('platformUsers');ElMessage.success(editingAdmin.value?'管理员信息已更新':'管理员创建成功')}
async function resetPassword(row:any){const r:any=await post(`/platform-users/${row.id}/reset-password`);await ElMessageBox.alert(`临时密码：${r.temporaryPassword}`,'密码重置成功',{confirmButtonText:'我已记下'});}
async function toggleAdmin(row:any){await post(`/platform-users/${row.id}/toggle-status`);await select('platformUsers');ElMessage.success('账号状态已更新')}
async function submitReport(){await act('/reports/submit','模拟上报已完成',{businessType:'WORKER',businessId:1})}
async function mockAttendance(){await act('/attendance/mock-generate','已生成今日模拟考勤',{projectId:scope.value.id,count:10})}
async function loadEducationOptions(){[projectWorkers.value,educationCourses.value]=await Promise.all([get(`/workers?projectId=${scope.value.id}`),get(`/education/courses?projectId=${scope.value.id}`)])}
async function openCourse(row?:any){questionBank.value=await get(`/education/questions?projectId=${scope.value.id}`);editingCourse.value=!!row;courseForm.value=row?{...row,questionIds:[...(row.questionIds||[])]}:{projectId:scope.value.id,courseType:'入场安全教育',passScore:80,validDays:365,status:'ACTIVE',questionIds:[]};courseDialog.value=true}
async function saveCourse(){try{if(editingCourse.value)await put(`/education/courses/${courseForm.value.id}`,courseForm.value);else await post('/education/courses',courseForm.value);courseDialog.value=false;await select('courses');ElMessage.success(editingCourse.value?'课程已更新':'课程已创建')}catch(e:any){ElMessage.error(e.message)}}
async function deleteCourse(row:any){try{await ElMessageBox.confirm(`确定删除课程“${row.name}”吗？`,'删除课程',{type:'warning'});await del(`/education/courses/${row.id}`);await select('courses');ElMessage.success('课程已删除')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
function optionItems(options:string){return questionOptions(options).map(x=>x.replace(/^[A-ZＡ-Ｚ][.、．]\s*/i,''))}
function answerOptions(){return (questionForm.value.optionItems||[]).map((x:string,i:number)=>({label:`${String.fromCharCode(65+i)}. ${x}`,value:String.fromCharCode(65+i)}))}
function changeQuestionType(){if(questionForm.value.questionType==='判断'){questionForm.value.optionItems=['正确','错误'];questionForm.value.answerValues='A'}else{questionForm.value.optionItems=['',''];questionForm.value.answerValues=questionForm.value.questionType==='多选'?[]:'A'}}
function addQuestionOption(){questionForm.value.optionItems.push('')}
function removeQuestionOption(index:number){if(questionForm.value.optionItems.length>2)questionForm.value.optionItems.splice(index,1)}
function openQuestion(row?:any){editingQuestion.value=!!row;const items=row?optionItems(row.options):['',''];questionForm.value=row?{...row,optionItems:items,answerValues:row.questionType==='多选'?(row.correctAnswer||'').split(',').filter(Boolean):row.correctAnswer}:{projectId:scope.value.id,questionType:'单选',score:10,status:'ACTIVE',optionItems:items,answerValues:'A'};questionDialog.value=true}
async function saveQuestion(){try{const options=(questionForm.value.optionItems||[]).map((x:string,i:number)=>`${String.fromCharCode(65+i)}.${x.trim()}`).join('；'),correctAnswer=Array.isArray(questionForm.value.answerValues)?questionForm.value.answerValues.join(','):questionForm.value.answerValues;const payload={...questionForm.value,projectId:scope.value.id,options,correctAnswer};if(editingQuestion.value)await put(`/education/questions/${questionForm.value.id}`,payload);else await post('/education/questions',payload);questionDialog.value=false;await select('questions');ElMessage.success(editingQuestion.value?'考题已更新':'考题已创建')}catch(e:any){ElMessage.error(e.message)}}
async function deleteQuestion(row:any){try{await ElMessageBox.confirm('确定删除该考题吗？','删除考题',{type:'warning'});await del(`/education/questions/${row.id}`);await select('questions');ElMessage.success('考题已删除')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
async function openLedger(){await loadEducationOptions();if(!projectWorkers.value.length)return ElMessage.warning('请先创建劳务工人');ledgerForm.value={workerId:projectWorkers.value[0].id,educationType:'入场安全教育',educationMethod:'线下教育',educationDate:new Date().toISOString().slice(0,10),courseName:'线下入场安全教育',teacher:'',classHours:2,passed:true,validStartDate:new Date().toISOString().slice(0,10),validEndDate:new Date(Date.now()+365*86400000).toISOString().slice(0,10)};ledgerDialog.value=true}
async function saveLedger(){try{await post('/education/ledger/offline',ledgerForm.value);ledgerDialog.value=false;await select('ledger');ElMessage.success('线下教育台账已录入，人员教育状态已同步')}catch(e:any){ElMessage.error(e.message)}}
async function markLedger(row:any,passed:boolean){await act(`/education/ledger/${row.id}/mark-${passed?'pass':'fail'}`,passed?'台账已标记通过':'台账已标记未通过')}
function openTrainingTask(row?:any){editingTrainingTask.value=!!row;trainingTaskForm.value=row?{...row,targetIds:[...(row.targetIds||[])]}:{projectId:scope.value.id,courseId:educationCourses.value[0]?.id,targetType:'ALL',targetIds:[],status:'ACTIVE'};trainingTaskDialog.value=true}
async function saveTrainingTask(){try{const form={...trainingTaskForm.value,targetIds:(trainingTaskForm.value.targetIds||[]).join(',')};if(editingTrainingTask.value)await put(`/education/training-tasks/${form.id}`,form);else await post('/education/training-tasks',form);trainingTaskDialog.value=false;await select('trainingTasks');ElMessage.success(editingTrainingTask.value?'培训任务已更新':'培训任务已创建')}catch(e:any){ElMessage.error(e.message)}}
async function deleteTrainingTask(row:any){try{await ElMessageBox.confirm(`确定删除培训任务“${row.name}”吗？`,'删除培训任务',{type:'warning'});await del(`/education/training-tasks/${row.id}`);await select('trainingTasks');ElMessage.success('培训任务已删除')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
async function showTrainingQr(row:any){qrUrl.value=`${location.origin}${import.meta.env.BASE_URL}mobile/training/${row.taskToken}`;qrDataUrl.value=await QRCode.toDataURL(qrUrl.value,{width:320,margin:2,errorCorrectionLevel:'M'});qrDialog.value=true}
async function regenerateTrainingQr(row:any){const r:any=await post(`/education/training-tasks/${row.id}/regenerate-token`);await select('trainingTasks');await showTrainingQr(r)}
function areaName(id:number){return projectAreas.value.find(a=>a.id===id)?.areaName||'未绑定区域'}
async function openDevice(row?:any){if(!projectAreas.value.length)projectAreas.value=await get(`/project-areas?projectId=${scope.value.id}`);editingDevice.value=!!row;deviceForm.value=row?{...row}:{projectId:scope.value.id,brand:'宇泛',deviceType:'人脸考勤机',status:'ONLINE'};deviceDialog.value=true}
async function saveDevice(){try{if(editingDevice.value)await put(`/devices/${deviceForm.value.id}`,deviceForm.value);else await post('/devices',deviceForm.value);deviceDialog.value=false;await select('devices');ElMessage.success(editingDevice.value?'设备已更新':'设备已创建并关联区域')}catch(e:any){ElMessage.error(e.message)}}
async function deleteDevice(row:any){try{await ElMessageBox.confirm(`确定删除设备“${row.deviceName}”吗？`,'删除设备',{type:'warning'});await del(`/devices/${row.id}`);await select('devices');ElMessage.success('设备已删除')}catch(e:any){if(e!=='cancel'&&e!=='close')ElMessage.error(e.message)}}
async function verifyTraining(){try{trainingIdentity.value=await post(`/mobile/training/${trainingToken}/verify`,trainingVerify.value);trainingAnswers.value=Object.fromEntries(trainingIdentity.value.questions.filter((q:any)=>q.questionType==='多选').map((q:any)=>[q.id,[]]))}catch(e:any){ElMessage.error(e.message)}}
async function submitTraining(){try{trainingResult.value=await post(`/mobile/training/${trainingToken}/submit`,{workerId:trainingIdentity.value.workerId,answers:trainingAnswers.value})}catch(e:any){ElMessage.error(e.message)}}
function logout(){session.logout();logged.value=false}
onMounted(async()=>{if(h5Entry)return;if(trainingToken){try{trainingPage.value=await get(`/mobile/training/${trainingToken}`)}catch(e:any){ElMessage.error(e.message)};return}if(mobileToken){try{mobileWorker.value=await get(`/mobile/worker/${mobileToken}`)}catch(e:any){ElMessage.error(e.message)};return}if(screenProjectId){const refresh=async()=>screenData.value=await get(`/screen/project/${screenProjectId}`);await refresh();window.setInterval(refresh,30000);return}if(logged.value){await loadScopeOptions();await select(scope.value.type==='platform'?'platformDashboard':scope.value.type==='company'?'companyDashboard':'dashboard')}})
</script>

<template>
<ProjectScreen v-if="screenProjectId" :data="screenData"/>
<div v-else-if="h5Entry" class="h5-entry"><div class="h5-entry-brand"><span class="brand-mark">BG</span><div><b>BuildGuard 现场入员</b><small>项目管理员 / 班组长专用</small></div></div><div v-if="!h5Logged" class="h5-entry-card"><h2>身份验证</h2><p>仅项目管理员和已启用 H5 权限的班组长可以登录。</p><el-form label-position="top" size="large"><el-form-item required label="手机号 / 登录账号"><el-input v-model="h5LoginForm.username" inputmode="tel"/></el-form-item><el-form-item required label="密码"><el-input v-model="h5LoginForm.password" type="password" show-password @keyup.enter="h5Login"/></el-form-item><el-button type="primary" @click="h5Login">登录并开始入员</el-button></el-form></div><div v-else class="h5-entry-card"><div class="h5-user"><div class="avatar">{{h5User.name?.slice(0,1)}}</div><div><b>{{h5User.name}}</b><small>{{h5User.actorType==='TEAM_LEADER'?'班组长，只能新增本班组人员':'项目管理员'}}</small></div></div><div class="h5-photo-grid"><label class="h5-photo required-photo"><img v-if="h5Worker.idCardPhotoUrl" :src="h5Worker.idCardPhotoUrl"/><span v-else>身份证正面</span><input type="file" accept="image/*" capture="environment" @change="h5Ocr"/></label><label class="h5-photo required-photo"><img v-if="h5Worker.idCardBackPhotoUrl" :src="h5Worker.idCardBackPhotoUrl"/><span v-else>身份证反面</span><input type="file" accept="image/*" capture="environment" @change="readH5Photo($event,'idCardBackPhotoUrl')"/></label><label class="h5-photo face required-photo"><img v-if="h5Worker.avatarUrl" :src="h5Worker.avatarUrl"/><span v-else>人脸照片</span><input type="file" accept="image/*" capture="environment" @change="readH5Photo($event,'avatarUrl')"/></label></div><el-form label-position="top"><el-form-item required label="所属项目"><el-select v-model="h5Worker.projectId" placeholder="请选择" :disabled="h5User.actorType==='TEAM_LEADER'" @change="h5ProjectChanged"><el-option v-for="p in h5Options.projects" :key="p.id" :label="p.projectName" :value="p.id"/></el-select></el-form-item><el-form-item required label="所属班组"><el-select v-model="h5Worker.teamId" placeholder="请选择" :disabled="h5User.actorType==='TEAM_LEADER'"><el-option v-for="t in h5Options.teams.filter((x:any)=>x.projectId===h5Worker.projectId)" :key="t.id" :label="t.teamName" :value="t.id"/></el-select></el-form-item><el-form-item required label="姓名"><el-input v-model="h5Worker.name"/></el-form-item><el-form-item required label="身份证号"><el-input v-model="h5Worker.idCardNo"/></el-form-item><el-form-item required label="手机号"><el-input v-model="h5Worker.phone" inputmode="tel"/></el-form-item><el-form-item required label="工种"><el-select v-model="h5Worker.workType" placeholder="请选择" filterable allow-create><el-option v-for="w in h5Options.workTypes" :key="w.id" :label="w.name" :value="w.name"/></el-select></el-form-item><el-button type="primary" size="large" :disabled="!h5Worker.name||!h5Worker.idCardNo||!h5Worker.phone||!h5Worker.idCardPhotoUrl||!h5Worker.idCardBackPhotoUrl||!h5Worker.avatarUrl||!h5Worker.teamId" @click="h5Submit">保存人员并自动下发设备</el-button></el-form></div></div>
<div v-else-if="trainingToken" class="mobile-page training-page"><div class="mobile-brand"><span class="brand-mark">BG</span><div><b>BuildGuard 安全教育</b><small>扫码培训与考试</small></div></div><div v-if="trainingPage" class="training-card"><template v-if="trainingResult"><el-result :icon="trainingResult.passed?'success':'warning'" :title="trainingResult.passed?'考试通过':'考试未通过'" :sub-title="`得分 ${trainingResult.score}，通过分数 ${trainingResult.passScore}`"/></template><template v-else-if="trainingIdentity"><h2>{{trainingPage.taskName}}</h2><p>{{trainingIdentity.workerName}}，请完成以下考题</p><div v-for="(q,index) in trainingIdentity.questions" :key="q.id" class="question-card"><b>{{index+1}}. {{q.questionContent}}（{{q.score}} 分）</b><el-checkbox-group v-if="q.questionType==='多选'" v-model="trainingAnswers[q.id]"><el-checkbox v-for="option in questionOptions(q.options)" :key="option" :value="option.slice(0,1)" :label="option.slice(0,1)">{{option}}</el-checkbox></el-checkbox-group><el-radio-group v-else-if="questionOptions(q.options).length" v-model="trainingAnswers[q.id]"><el-radio v-for="option in questionOptions(q.options)" :key="option" :value="option.slice(0,1)">{{option}}</el-radio></el-radio-group><el-input v-else v-model="trainingAnswers[q.id]" placeholder="请输入答案"/></div><el-button type="primary" size="large" @click="submitTraining">提交考试</el-button></template><template v-else><h2>{{trainingPage.taskName}}</h2><el-tag>{{trainingPage.courseType}}</el-tag><p>{{trainingPage.courseName}}</p><div class="course-content">{{trainingPage.content||'请完成身份验证后开始本次安全教育考试。'}}</div><el-form label-position="top"><el-form-item required label="手机号"><el-input v-model="trainingVerify.phone"/></el-form-item><el-form-item required label="身份证后六位"><el-input v-model="trainingVerify.idCardSuffix" maxlength="6"/></el-form-item><el-button type="primary" size="large" @click="verifyTraining">验证身份并开始考试</el-button></el-form></template></div></div>
<div v-else-if="mobileToken" class="mobile-page"><div class="mobile-brand"><span class="brand-mark">BG</span><div><b>BuildGuard</b><small>智慧工地实名制人员信息</small></div></div><div v-if="mobileWorker" class="worker-pass"><div class="pass-top"><img v-if="mobileWorker.avatarUrl" class="pass-photo" :src="mobileWorker.avatarUrl"/><div v-else class="avatar pass-avatar">工</div><div><span>实名认证人员</span><h1>{{mobileWorker.name}}</h1><p>{{mobileWorker.workType}} · {{mobileWorker.workerType}}</p></div><el-tag size="large" :type="tag(mobileWorker.accessStatus)[1]">{{tag(mobileWorker.accessStatus)[0]}}</el-tag></div><div class="pass-grid"><div><span>身份证号</span><b>{{mobileWorker.idCardNo}}</b></div><div><span>手机号</span><b>{{mobileWorker.phone}}</b></div><div><span>进场状态</span><b>{{tag(mobileWorker.status)[0]}}</b></div><div><span>安全教育</span><b>{{tag(mobileWorker.safetyEducationStatus)[0]}}</b></div><div class="wide"><span>所属项目</span><b>{{mobileWorker.projectName}}</b></div><div><span>参建单位</span><b>{{mobileWorker.participantUnitName}}</b></div><div><span>所属班组</span><b>{{mobileWorker.teamName}}</b></div><div class="wide"><span>允许进入区域</span><b>{{mobileWorker.allowedAreas?.join('、')||'未配置'}}</b></div><div class="wide"><span>最近考勤</span><b>{{mobileWorker.lastAttendanceTime}}</b></div></div><div class="verified"><span class="green status-dot"></span>信息由 BuildGuard 智慧工地系统核验</div></div></div>
<div v-else-if="!logged" class="login-page">
  <div class="login-art"><div class="brand"><span class="brand-mark">BG</span><span>BuildGuard</span></div><div class="hero"><div class="hero-kicker">SMART CONSTRUCTION PLATFORM</div><h1>让每一次进场<br>都有迹可循</h1><p>实名制、门禁考勤、安全教育与监管上报的一体化智慧工地平台</p><div class="hero-stats"><span><b>实名制</b>人员档案</span><span><b>门禁</b>区域权限</span><span><b>安全</b>教育闭环</span></div></div></div>
  <div class="login-panel"><div class="login-box"><h2>欢迎回来</h2><p>登录智慧工地系统管理后台</p><el-form label-position="top" size="large"><el-form-item required label="账号"><el-input v-model="loginForm.username" placeholder="请输入账号"/></el-form-item><el-form-item required label="密码"><el-input v-model="loginForm.password" type="password" show-password @keyup.enter="login"/></el-form-item><el-button type="primary" :loading="loading" @click="login">登录系统</el-button></el-form><div class="demo-tip">演示账号：admin / 123456</div></div></div>
</div>
<div v-else class="shell">
 <aside><div class="side-brand"><span class="brand-mark">BG</span><div><b>BuildGuard</b><small>{{session.role==='SUPER_ADMIN'?'超级管理员控制台':'企业管理控制台'}}</small></div></div><button class="scope-switch" @click="scopeDialog=true"><div><small>管理范围 · {{scopeTypeName}}</small><b>{{scope.name}}</b></div><el-icon><ArrowDown/></el-icon></button><nav><template v-for="g in menus" :key="g.key"><div v-if="!g.children" :class="['nav-item nav-level-one',{active:active===g.key}]" @click="select(g.key)"><el-icon><component :is="g.icon"/></el-icon>{{g.label}}</div><template v-else><div :class="['nav-category',{open:expanded.includes(g.key)}]" @click="toggleMenu(g.key)"><span><el-icon><component :is="g.icon"/></el-icon>{{g.label}}</span><el-icon><ArrowDown/></el-icon></div><div v-show="expanded.includes(g.key)" class="nav-children"><div v-for="m in g.children" :key="m[0]" :class="['nav-item',{active:active===m[0]}]" @click="select(m[0])"><el-icon><component :is="m[2]"/></el-icon>{{m[1]}}</div></div></template></template></nav></aside>
 <main><header><div class="page-heading"><span class="scope-title"><i :class="scope.type"></i>{{scope.type==='project'?(scope.companyName+' / '+scope.name):scope.name}}</span><el-button v-if="scope.type==='project'" @click="backCompany">返回企业级</el-button></div><div class="header-actions"><el-input v-model="search" :prefix-icon="Search" placeholder="搜索当前列表"/><div class="user"><div class="avatar">{{session.name?.slice(0,1)||'管'}}</div><div><b>{{session.name}}</b><small>{{session.role==='SUPER_ADMIN'?'拥有全部企业和项目权限':'可访问 '+session.companyIds.length+' 家授权企业'}}</small></div></div><el-button circle :icon="SwitchButton" @click="logout"/></div></header>
 <section class="content">
  <template v-if="active==='platformDashboard'">
   <div class="platform-hero"><div><span>SUPER ADMIN CONSOLE</span><h2>平台运营总览</h2><p>统一管理企业、管理账号与全部项目访问权限。</p></div><el-button type="primary" size="large" @click="scopeDialog=true">进入企业 / 项目</el-button></div>
   <div class="metrics platform-metrics"><div v-for="m in [{l:'管理账号',v:dashboard.accountCount,u:'个',c:'#247eff'},{l:'企业数量',v:dashboard.companyCount,u:'家',c:'#16b383'},{l:'全部项目',v:dashboard.projectCount,u:'个',c:'#8c63e9'},{l:'在册人员',v:dashboard.workerCount,u:'人',c:'#f1a33c'}]" class="metric"><span :style="{background:m.c}"></span><div><small>{{m.l}}</small><b>{{m.v}}<i>{{m.u}}</i></b></div></div></div>
   <div class="platform-grid"><el-card><template #header><div class="card-head"><b>企业运营概览</b><el-button link type="primary" @click="select('companies')">企业管理</el-button></div></template><div v-for="t in scopeOptions.companies" class="tenant-overview"><div class="company-mark">{{t.name.slice(0,1)}}</div><div><b>{{t.name}}</b><small>{{scopeOptions.projects.filter((p:any)=>p.companyId===t.id).length}} 个项目 · {{t.contactName}}</small></div><el-tag type="success">正常</el-tag></div></el-card><el-card><template #header><b>超级管理员职责</b></template><div class="admin-duty"><span>01</span><div><b>企业全生命周期管理</b><p>创建、启停企业并分配管理账号。</p></div></div><div class="admin-duty"><span>02</span><div><b>跨企业权限管理</b><p>一个管理账号可以被授权访问多家企业。</p></div></div><div class="admin-duty"><span>03</span><div><b>平台级配置维护</b><p>维护平台参数、接入能力与运行策略。</p></div></div></el-card></div>
  </template>
  <template v-else-if="active==='companyDashboard'">
   <div class="banner"><div><span>企业运行总览</span><h3>{{scope.name}}</h3><p>从企业级查看全部项目运行指标，并可下钻进入具体项目。</p></div></div>
   <div class="metrics"><div v-for="m in [{l:'项目总数',v:dashboard.projectCount,u:'个',c:'#247eff'},{l:'在建项目',v:dashboard.activeProjectCount,u:'个',c:'#16b383'},{l:'总工人数',v:dashboard.workerCount,u:'人',c:'#8c63e9'},{l:'今日出勤',v:dashboard.todayAttendance,u:'人',c:'#19a8b8'},{l:'安全教育通过率',v:dashboard.safetyRate,u:'%',c:'#f1a33c'},{l:'上报成功率',v:dashboard.reportRate,u:'%',c:'#ed5d5d'}]" class="metric"><span :style="{background:m.c}"></span><div><small>{{m.l}}</small><b>{{m.v}}<i>{{m.u}}</i></b></div></div></div>
   <el-card class="dashboard-section"><template #header><div class="card-head"><b>项目列表</b><el-button link type="primary" @click="select('projects')">{{canManageCompany?'管理项目':'查看项目'}}</el-button></div></template><el-table :data="dashboardProjects"><el-table-column prop="projectName" label="项目名称" min-width="220"/><el-table-column prop="projectCode" label="项目编码"/><el-table-column prop="managerName" label="负责人"/><el-table-column prop="address" label="项目地址" min-width="220"/><el-table-column prop="status" label="状态"/><el-table-column label="操作" width="100"><template #default="{row}"><el-button link type="primary" @click="enterProject(row)">进入项目</el-button></template></el-table-column></el-table></el-card>
   <el-card class="dashboard-section"><template #header><div class="card-head"><b>项目健康度统计</b><el-button link type="primary" @click="select('projectHealth')">查看全部</el-button></div></template><el-table :data="dashboardHealth"><el-table-column prop="projectName" label="项目名称" min-width="220"/><el-table-column prop="healthScore" label="健康度"/><el-table-column prop="todayAttendance" label="今日出勤"/><el-table-column prop="safetyRate" label="教育通过率"/><el-table-column label="健康状态"><template #default="{row}"><el-tag :type="row.healthStatus==='正常'?'success':row.healthStatus==='关注'?'warning':'danger'">{{row.healthStatus}}</el-tag></template></el-table-column><el-table-column label="操作" width="100"><template #default="{row}"><el-button link type="primary" @click="enterProject(row)">进入项目</el-button></template></el-table-column></el-table></el-card>
  </template>
  <template v-else-if="active==='dashboard'">
   <div class="banner"><div><span>项目运行总览</span><h3>下午好，平台管理员</h3><p>今日项目运行平稳，设备在线率良好。当前有 <b>{{dashboard.abnormalCount}}</b> 条异常考勤待处理。</p></div><div class="banner-time"><b>{{new Date().toLocaleDateString('zh-CN',{month:'long',day:'numeric'})}}</b><span>安全生产第 168 天</span></div></div>
   <div class="metrics"><div v-for="m in [{l:'项目总人数',v:dashboard.workerCount,u:'人',c:'#247eff'},{l:'今日出勤',v:dashboard.todayAttendance,u:'人次',c:'#16b383'},{l:'当前在场',v:dashboard.onSiteCount,u:'人',c:'#8c63e9'},{l:'安全教育通过率',v:dashboard.safetyRate,u:'%',c:'#19a8b8'},{l:'设备在线数',v:dashboard.onlineDevices,u:'台',c:'#f1a33c'},{l:'异常考勤',v:dashboard.abnormalCount,u:'条',c:'#ed5d5d'}]" class="metric"><span :style="{background:m.c}"></span><div><small>{{m.l}}</small><b>{{m.v}}<i>{{m.u}}</i></b></div></div></div>
   <div class="charts"><el-card><template #header><b>近 7 日出勤趋势</b></template><div id="trend" class="chart"></div></el-card><el-card><template #header><b>工种分布</b></template><div id="pie" class="chart"></div></el-card></div>
   <el-card><template #header><div class="card-head"><b>实时考勤动态</b><el-button link type="primary" @click="select('attendance')">查看全部</el-button></div></template><el-table :data="rows.slice(0,6)"><el-table-column prop="workerName" label="人员"/><el-table-column prop="areaName" label="区域"/><el-table-column prop="deviceName" label="设备"/><el-table-column prop="attendanceTime" label="考勤时间"/><el-table-column label="结果"><template #default="{row}"><el-tag :type="tag(row.accessResult)[1]">{{tag(row.accessResult)[0]}}</el-tag></template></el-table-column></el-table></el-card>
  </template>
  <template v-else-if="active==='idcard'"><el-card class="id-card"><div class="scanner"><el-icon><Connection/></el-icon></div><h2>身份证读卡器</h2><p>连接华视 CVR-100U / 精伦 iDR210 本地读卡助手，读取实名信息</p><el-button type="primary" size="large" @click="mockCard">模拟读取身份证</el-button><div v-if="newWorker.name" class="card-result"><div class="avatar big">证</div><div><h3>{{newWorker.name}} · {{newWorker.gender}}</h3><p>{{newWorker.idCardNo}}</p><p>{{newWorker.address}}</p></div><el-button type="primary" plain @click="dialog=true">创建人员档案</el-button></div></el-card></template>
  <template v-else-if="['companyWorkers','companyAttendance'].includes(active)"><el-card><template #header><div class="card-head"><div><b>{{title}}</b><span>按企业下属项目汇总，数据将在录入业务数据后自动展示</span></div><el-button :icon="Refresh" @click="select(active)">刷新</el-button></div></template><el-table :data="rows" height="calc(100vh - 210px)"><el-table-column prop="projectName" label="项目名称" min-width="220"/><template v-if="active==='companyWorkers'"><el-table-column prop="workerCount" label="人员总数"/><el-table-column prop="onSiteCount" label="当前在场"/><el-table-column prop="safetyRate" label="教育通过率"/><el-table-column prop="teamCount" label="班组数量"/></template><template v-else><el-table-column prop="todayAttendance" label="今日出勤"/><el-table-column prop="onSiteCount" label="当前在场"/><el-table-column prop="abnormalCount" label="异常考勤"/><el-table-column prop="attendanceRate" label="出勤率"/></template><template #empty><el-empty description="暂无汇总数据，请先创建项目并录入业务数据"/></template></el-table></el-card></template>
	  <template v-else-if="active==='permissions'"><el-card><template #header><div class="card-head"><div><b>区域权限</b><span>按人员配置允许进入区域，保存后可下发对应区域设备</span></div><div class="card-actions"><el-button :icon="Refresh" @click="select('permissions')">刷新</el-button><el-button type="primary" :icon="Plus" @click="openPermission()">配置区域权限</el-button></div></div></template><el-table :data="projectWorkers" height="calc(100vh - 210px)"><el-table-column prop="personCode" label="人员编号" width="190"/><el-table-column prop="name" label="姓名"/><el-table-column prop="workType" label="工种"/><el-table-column label="允许进入区域" min-width="320"><template #default="{row}">{{permissionAreas(row.id)}}</template></el-table-column><el-table-column label="安全教育"><template #default="{row}"><el-tag :type="tag(row.safetyEducationStatus)[1]">{{tag(row.safetyEducationStatus)[0]}}</el-tag></template></el-table-column><el-table-column label="门禁状态"><template #default="{row}"><el-tag :type="tag(row.accessStatus)[1]">{{tag(row.accessStatus)[0]}}</el-tag></template></el-table-column><el-table-column label="操作" width="210"><template #default="{row}"><el-button link type="primary" @click="openPermission(row)">配置区域</el-button><el-button link type="success" @click="syncWorker(row)">下发设备</el-button></template></el-table-column></el-table></el-card></template>
	  <template v-else-if="active==='attendanceStat'"><div v-if="!attendanceStats.trend" class="empty-feature"><el-icon><DataBoard/></el-icon><h2>考勤统计</h2><p>统计今日考勤、异常原因和近 7 日趋势。</p><el-button type="primary" @click="loadAttendanceStats">加载考勤统计</el-button></div><template v-else><div class="card-head stat-head"><div><b>考勤统计</b><span>统计口径：当前项目今日考勤记录</span></div><el-button :icon="Refresh" @click="loadAttendanceStats">刷新</el-button></div><div class="metrics attendance-metrics"><div v-for="m in [{l:'今日出勤人数',v:attendanceStats.todayAttendance,u:'人',c:'#247eff'},{l:'当前在场人数',v:attendanceStats.onSiteCount,u:'人',c:'#16b383'},{l:'今日进场次数',v:attendanceStats.inCount,u:'次',c:'#8c63e9'},{l:'今日出场次数',v:attendanceStats.outCount,u:'次',c:'#19a8b8'},{l:'正常考勤',v:attendanceStats.allowCount,u:'条',c:'#36b37e'},{l:'异常考勤',v:attendanceStats.abnormalCount,u:'条',c:'#ed5d5d'}]" class="metric"><span :style="{background:m.c}"></span><div><small>{{m.l}}</small><b>{{m.v}}<i>{{m.u}}</i></b></div></div></div><div class="stat-grid"><el-card><template #header><b>近 7 日考勤趋势</b></template><el-table :data="attendanceStats.trend"><el-table-column prop="date" label="日期"/><el-table-column prop="attendanceCount" label="出勤人数"/><el-table-column prop="recordCount" label="考勤次数"/><el-table-column prop="abnormalCount" label="异常次数"/></el-table></el-card><el-card><template #header><b>今日区域统计</b></template><el-table :data="attendanceStats.areaStats"><el-table-column prop="name" label="区域"/><el-table-column prop="count" label="考勤次数"/></el-table></el-card><el-card><template #header><b>异常原因统计</b></template><el-table :data="attendanceStats.abnormalReasonStats"><el-table-column prop="name" label="异常原因"/><el-table-column prop="count" label="次数"/></el-table></el-card></div></template></template>
