    <el-table-column v-if="active==='companies'" label="操作" width="150" fixed="right"><template #default="{row}"><el-button link type="primary" @click="openCompany(row)">编辑</el-button><el-button link type="danger" @click="deleteCompany(row)">删除</el-button></template></el-table-column>
    <el-table-column v-if="active==='projects'" label="操作" width="220" fixed="right"><template #default="{row}"><el-button link type="primary" @click="enterProject(row)">进入项目</el-button><template v-if="canManageCompany"><el-button link type="primary" @click="openProject(row)">编辑</el-button><el-button link type="danger" @click="deleteProject(row)">删除</el-button></template></template></el-table-column>
    <el-table-column v-if="active==='companyUsers'" label="操作" width="230" fixed="right"><template #default="{row}"><template v-if="row.role!=='COMPANY_ADMIN'"><el-button link type="primary" @click="openCompanyUser(row)">编辑</el-button><el-button link type="warning" @click="resetCompanyUser(row)">重置密码</el-button><el-button link type="danger" @click="deleteCompanyUser(row)">删除</el-button></template><el-tag v-else type="info">由超级管理员维护</el-tag></template></el-table-column>
    <el-table-column v-if="active==='projectUsers'" label="操作" width="160" fixed="right"><template #default="{row}"><el-button link type="primary" @click="openProjectUser(row)">编辑</el-button><el-button link type="danger" @click="deleteProjectUser(row)">移除</el-button></template></el-table-column>
    <el-table-column v-if="['companyRoles','projectRoles'].includes(active)" label="操作" width="160" fixed="right"><template #default="{row}"><el-button link type="primary" @click="openRole(row)">编辑</el-button><el-button v-if="!row.systemRole" link type="danger" @click="deleteRole(row)">删除</el-button></template></el-table-column>
    <el-table-column v-if="active==='units'" label="操作" width="150" fixed="right"><template #default="{row}"><el-button link type="primary" @click="openUnit(row)">编辑</el-button><el-button link type="danger" @click="deleteUnit(row)">删除</el-button></template></el-table-column>
    <el-table-column v-if="active==='areas'" label="操作" width="150" fixed="right"><template #default="{row}"><el-button link type="primary" @click="openArea(row)">编辑</el-button><el-button link type="danger" @click="deleteArea(row)">删除</el-button></template></el-table-column>
    <el-table-column v-if="active==='teams'" label="操作" width="150" fixed="right"><template #default="{row}"><el-button link type="primary" @click="openTeam(row)">编辑</el-button><el-button link type="danger" @click="deleteTeam(row)">删除</el-button></template></el-table-column>
    <el-table-column v-if="active==='platformUsers'" label="操作" width="250" fixed="right"><template #default="{row}"><el-button link type="primary" @click="openAdmin(row)">编辑</el-button><el-button link type="warning" @click="resetPassword(row)">重置密码</el-button><el-button link :type="row.status==='ACTIVE'?'danger':'success'" @click="toggleAdmin(row)">{{row.status==='ACTIVE'?'禁用':'启用'}}</el-button></template></el-table-column>
   </el-table></el-card>
  </template>
 </section></main>
</div>
<el-drawer v-model="workerDetailDrawer" :title="`${workerDetail.worker?.name||''} · 实名制人员档案`" size="78%"><div v-if="workerDetail.worker" class="worker-detail-head"><img v-if="workerDetail.worker.avatarUrl" :src="workerDetail.worker.avatarUrl"/><div v-else class="avatar big">人</div><div><h2>{{workerDetail.worker.name}}</h2><p>{{workerDetail.worker.personCode}} · {{workerDetail.worker.workType||'未配置工种'}}</p><el-tag :type="tag(workerDetail.worker.status)[1]">{{tag(workerDetail.worker.status)[0]}}</el-tag><el-tag :type="tag(workerDetail.worker.safetyEducationStatus)[1]">{{tag(workerDetail.worker.safetyEducationStatus)[0]}}</el-tag><el-tag :type="tag(workerDetail.worker.accessStatus)[1]">{{tag(workerDetail.worker.accessStatus)[0]}}</el-tag></div></div><el-tabs v-model="workerDetailTab"><el-tab-pane label="基本信息" name="basic"><el-descriptions :column="3" border><el-descriptions-item label="姓名">{{workerDetail.worker.name}}</el-descriptions-item><el-descriptions-item label="身份证号">{{workerDetail.worker.idCardNo}}</el-descriptions-item><el-descriptions-item label="手机号">{{workerDetail.worker.phone||'-'}}</el-descriptions-item><el-descriptions-item label="性别 / 民族">{{workerDetail.worker.gender||'-'}} / {{workerDetail.worker.nation||'-'}}</el-descriptions-item><el-descriptions-item label="出生日期">{{workerDetail.worker.birthDate||'-'}}</el-descriptions-item><el-descriptions-item label="技能等级">{{workerDetail.worker.skillLevel||'-'}}</el-descriptions-item><el-descriptions-item label="地址" :span="3">{{workerDetail.worker.address||'-'}}</el-descriptions-item><el-descriptions-item label="紧急联系人">{{workerDetail.worker.emergencyContact||'-'}}</el-descriptions-item><el-descriptions-item label="紧急电话">{{workerDetail.worker.emergencyPhone||'-'}}</el-descriptions-item><el-descriptions-item label="备注">{{workerDetail.worker.remark||'-'}}</el-descriptions-item></el-descriptions></el-tab-pane><el-tab-pane label="实名制资料" name="realname"><el-descriptions :column="3" border><el-descriptions-item label="人脸照片">{{workerDetail.worker.avatarUrl?'已采集，可下发设备':'未采集，禁止下发设备'}}</el-descriptions-item><el-descriptions-item label="身份证正面">{{workerDetail.worker.idCardPhotoUrl?'已采集':'未采集'}}</el-descriptions-item><el-descriptions-item label="身份证反面">{{workerDetail.worker.idCardBackPhotoUrl?'已采集':'未采集'}}</el-descriptions-item><el-descriptions-item label="实名制上报">{{tag(workerDetail.worker.realNameReportStatus)[0]}}</el-descriptions-item><el-descriptions-item label="合同状态">{{workerDetail.worker.contractStatus||'-'}}</el-descriptions-item><el-descriptions-item label="工资状态">{{workerDetail.worker.wageStatus||'-'}}</el-descriptions-item><el-descriptions-item label="银行卡号">{{workerDetail.worker.bankCardNo||'-'}}</el-descriptions-item></el-descriptions></el-tab-pane><el-tab-pane label="项目 / 单位 / 班组" name="organization"><el-descriptions :column="2" border><el-descriptions-item label="所属项目">{{workerDetail.project?.projectName||'-'}}</el-descriptions-item><el-descriptions-item label="所属参建单位">{{workerDetail.participantUnit?.unitName||'-'}}</el-descriptions-item><el-descriptions-item label="所属班组">{{workerDetail.team?.teamName||'-'}}</el-descriptions-item><el-descriptions-item label="工种">{{workerDetail.worker.workType||'-'}}</el-descriptions-item><el-descriptions-item label="入场日期">{{workerDetail.worker.entryDate||'-'}}</el-descriptions-item><el-descriptions-item label="退场日期">{{workerDetail.worker.exitDate||'-'}}</el-descriptions-item></el-descriptions></el-tab-pane><el-tab-pane label="区域权限" name="permission"><el-table :data="workerDetail.permissions"><el-table-column label="区域"><template #default="{row}">{{workerDetail.areas?.find((a:any)=>a.id===row.areaId)?.areaName||'-'}}</template></el-table-column><el-table-column prop="permissionStatus" label="权限状态"/><el-table-column prop="deviceSyncStatus" label="下发状态"/><el-table-column prop="validEndTime" label="有效期至"/></el-table></el-tab-pane><el-tab-pane label="安全教育记录" name="education"><el-table :data="workerDetail.educationLedger"><el-table-column prop="courseName" label="课程"/><el-table-column prop="educationMethod" label="方式"/><el-table-column prop="educationDate" label="教育日期"/><el-table-column prop="validEndDate" label="有效期至"/><el-table-column label="结果"><template #default="{row}"><el-tag :type="row.passed?'success':'danger'">{{row.passed?'通过':'未通过'}}</el-tag></template></el-table-column></el-table></el-tab-pane><el-tab-pane label="考勤记录" name="attendance"><el-table :data="workerDetail.attendance"><el-table-column prop="attendanceTime" label="考勤时间"/><el-table-column prop="areaName" label="区域"/><el-table-column prop="deviceName" label="设备"/><el-table-column prop="direction" label="方向"/><el-table-column prop="denyReason" label="异常原因"/></el-table></el-tab-pane><el-tab-pane label="设备下发记录" name="sync"><el-table :data="workerDetail.syncLogs"><el-table-column prop="deviceName" label="设备"/><el-table-column prop="actionType" label="动作"/><el-table-column prop="syncStatus" label="状态"/><el-table-column prop="errorMessage" label="结果"/></el-table></el-tab-pane><el-tab-pane label="上报记录" name="report"><el-table :data="workerDetail.reportLogs"><el-table-column prop="submittedAt" label="上报时间"/><el-table-column prop="status" label="状态"/><el-table-column prop="errorMessage" label="结果"/></el-table></el-tab-pane><el-tab-pane label="二维码" name="qr"><div class="empty-feature"><h3>人员现场核验二维码</h3><p>二维码扫码页仅展示脱敏后的基础信息、状态、区域权限和最近考勤。</p><el-button type="primary" @click="showQr(workerDetail.worker)">生成 / 查看二维码</el-button></div></el-tab-pane></el-tabs></el-drawer>
<el-dialog v-model="dialog" :title="editingWorker?'编辑劳务工人实名档案':'新增劳务工人实名档案'" width="880"><el-form label-position="top"><el-alert title="人脸照片用于下发人脸考勤机，未采集人脸照片的人员禁止下发设备。" type="warning" :closable="false"/><div class="worker-photo-row"><div class="photo-box required-photo"><img v-if="newWorker.avatarUrl" :src="newWorker.avatarUrl"/><span v-else>人脸照片</span><label class="upload-button"><input type="file" accept="image/*" @change="readWorkerPhoto($event,'avatarUrl')"/>上传人脸照片</label></div><div class="photo-box required-photo"><img v-if="newWorker.idCardPhotoUrl" :src="newWorker.idCardPhotoUrl"/><span v-else>身份证正面</span><label class="upload-button"><input type="file" accept="image/*" @change="readWorkerPhoto($event,'idCardPhotoUrl')"/>上传身份证正面</label></div><div class="photo-box required-photo"><img v-if="newWorker.idCardBackPhotoUrl" :src="newWorker.idCardBackPhotoUrl"/><span v-else>身份证反面</span><label class="upload-button"><input type="file" accept="image/*" @change="readWorkerPhoto($event,'idCardBackPhotoUrl')"/>上传身份证反面</label></div></div><el-divider content-position="left">基本信息</el-divider><div class="form-grid"><el-form-item required label="姓名"><el-input v-model="newWorker.name"/></el-form-item><el-form-item required label="身份证号"><el-input v-model="newWorker.idCardNo"/></el-form-item><el-form-item required label="手机号"><el-input v-model="newWorker.phone"/></el-form-item><el-form-item required label="性别"><el-select v-model="newWorker.gender"><el-option label="男" value="男"/><el-option label="女" value="女"/></el-select></el-form-item><el-form-item required label="民族"><el-input v-model="newWorker.nation"/></el-form-item><el-form-item required label="出生日期"><el-date-picker v-model="newWorker.birthDate" value-format="YYYY-MM-DD"/></el-form-item><el-form-item required label="地址"><el-input v-model="newWorker.address"/></el-form-item><el-form-item label="技能等级"><el-input v-model="newWorker.skillLevel"/></el-form-item><el-form-item required label="工种"><el-select v-model="newWorker.workType" clearable filterable placeholder="请选择平台配置的工种"><el-option v-if="newWorker.workType&&!workTypeOptions.some((x:any)=>x.name===newWorker.workType)" :label="newWorker.workType" :value="newWorker.workType"/><el-option v-for="w in workTypeOptions.filter((x:any)=>x.status==='ACTIVE')" :key="w.id" :label="w.name" :value="w.name"/></el-select></el-form-item><el-form-item required label="参建单位"><el-select v-model="newWorker.participantUnitId" clearable><el-option v-for="u in projectUnits" :key="u.id" :label="u.unitName" :value="u.id"/></el-select></el-form-item><el-form-item required label="班组"><el-select v-model="newWorker.teamId" clearable><el-option v-for="t in projectTeams.filter((x:any)=>!newWorker.participantUnitId||x.participantUnitId===newWorker.participantUnitId)" :key="t.id" :label="t.teamName" :value="t.id"/></el-select></el-form-item><el-form-item required label="人员状态"><el-select v-model="newWorker.status"><el-option label="待入场" value="WAIT_ENTRY"/><el-option label="在场" value="ON_SITE"/><el-option label="已退场" value="LEFT_SITE"/><el-option label="黑名单" value="BLACKLIST"/></el-select></el-form-item></div><el-divider content-position="left">从业与预留信息</el-divider><div class="form-grid"><el-form-item label="银行卡号（预留）"><el-input v-model="newWorker.bankCardNo"/></el-form-item><el-form-item label="合同状态"><el-select v-model="newWorker.contractStatus" clearable><el-option label="未签订" value="NOT_SIGNED"/><el-option label="已签订" value="SIGNED"/><el-option label="已到期" value="EXPIRED"/></el-select></el-form-item><el-form-item label="工资发放状态（预留）"><el-select v-model="newWorker.wageStatus" clearable><el-option label="未发放" value="NOT_PAID"/><el-option label="已发放" value="PAID"/><el-option label="异常" value="ABNORMAL"/></el-select></el-form-item><el-form-item label="紧急联系人"><el-input v-model="newWorker.emergencyContact"/></el-form-item><el-form-item label="紧急联系人电话"><el-input v-model="newWorker.emergencyPhone"/></el-form-item><el-form-item label="身份证读取"><el-button @click="mockCard">模拟读取身份证</el-button></el-form-item></div><el-form-item label="备注"><el-input v-model="newWorker.remark" type="textarea"/></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="saveWorker">保存人员档案</el-button></template></el-dialog>
<el-dialog v-model="workTypeDialog" :title="editingWorkType?'编辑工种':'新增工种'" width="620"><el-alert title="工种字典由平台统一维护，启用后的工种可在劳务人员档案中选择。" type="info" :closable="false"/><el-form label-position="top"><div class="form-grid"><el-form-item required label="工种编码"><el-input v-model="workTypeForm.code" placeholder="例如 CARPENTER"/></el-form-item><el-form-item required label="工种名称"><el-input v-model="workTypeForm.name" placeholder="例如 木工"/></el-form-item><el-form-item label="工种分类"><el-input v-model="workTypeForm.category" placeholder="例如 土建施工"/></el-form-item><el-form-item label="排序"><el-input-number v-model="workTypeForm.sortOrder" :min="0"/></el-form-item><el-form-item required label="状态"><el-select v-model="workTypeForm.status"><el-option label="正常" value="ACTIVE"/><el-option label="禁用" value="DISABLED"/></el-select></el-form-item><el-form-item label="备注"><el-input v-model="workTypeForm.remark"/></el-form-item></div></el-form><template #footer><el-button @click="workTypeDialog=false">取消</el-button><el-button type="primary" @click="saveWorkType">保存工种</el-button></template></el-dialog>
<el-dialog v-model="importDialog" title="批量导入预览" width="900"><el-alert :title="`校验通过 ${importPreview.validCount} 条，错误 ${importPreview.errorCount} 条`" :type="importPreview.errorCount?'warning':'success'" :closable="false"/><el-table :data="importRows" max-height="430" style="margin-top:14px"><el-table-column prop="name" label="姓名"/><el-table-column prop="idCardNo" label="身份证号" min-width="190"/><el-table-column prop="workType" label="工种"/><el-table-column prop="participantUnitName" label="参建单位"/><el-table-column prop="teamName" label="班组"/><el-table-column label="校验结果" min-width="220"><template #default="{row}"><el-tag :type="row.valid?'success':'danger'">{{row.valid?'通过':row.error}}</el-tag></template></el-table-column></el-table><template #footer><el-button @click="importDialog=false">取消</el-button><el-button type="primary" :disabled="importPreview.errorCount>0||!importPreview.validCount" @click="confirmImport">确认导入</el-button></template></el-dialog>
<el-dialog v-model="courseDialog" :title="editingCourse?'编辑教育课程':'新增教育课程'" width="760"><el-form label-position="top"><div class="form-grid"><el-form-item required label="课程名称"><el-input v-model="courseForm.name"/></el-form-item><el-form-item required label="课程类型"><el-select v-model="courseForm.courseType"><el-option v-for="s in ['入场安全教育','三级安全教育','专项安全教育','班前教育','临时教育','其他']" :key="s" :label="s" :value="s"/></el-select></el-form-item><el-form-item required label="通过分数"><el-input-number v-model="courseForm.passScore" :min="0" :max="100"/></el-form-item><el-form-item required label="有效期天数"><el-input-number v-model="courseForm.validDays" :min="1"/></el-form-item></div><el-form-item required label="课程内容"><el-input v-model="courseForm.content" type="textarea" :rows="4"/></el-form-item><el-form-item required label="课程考题"><el-select v-model="courseForm.questionIds" multiple filterable collapse-tags placeholder="从当前项目考题库中选择考题"><el-option v-for="q in questionBank" :key="q.id" :label="`[${q.questionType}] ${q.questionContent}`" :value="q.id"/></el-select><small class="form-tip">课程负责组卷，考题可被多个课程重复使用。</small></el-form-item></el-form><template #footer><el-button @click="courseDialog=false">取消</el-button><el-button type="primary" @click="saveCourse">保存课程</el-button></template></el-dialog>
<el-dialog v-model="questionDialog" :title="editingQuestion?'编辑题库考题':'新增题库考题'" width="760"><el-form label-position="top"><div class="form-grid"><el-form-item required label="题型"><el-select v-model="questionForm.questionType" @change="changeQuestionType"><el-option v-for="s in ['单选','多选','判断']" :key="s" :label="s" :value="s"/></el-select></el-form-item><el-form-item required label="分值"><el-input-number v-model="questionForm.score" :min="1"/></el-form-item></div><el-form-item required label="题目内容"><el-input v-model="questionForm.questionContent" type="textarea" :rows="2"/></el-form-item><el-form-item required label="选项"><div class="question-options"><div v-for="(option,index) in questionForm.optionItems" :key="index" class="question-option"><span>{{String.fromCharCode(65+index)}}.</span><el-input v-model="questionForm.optionItems[index]" :disabled="questionForm.questionType==='判断'" :placeholder="`请输入选项 ${String.fromCharCode(65+index)}`"/><el-button v-if="questionForm.questionType!=='判断'" link type="danger" :disabled="questionForm.optionItems.length<=2" @click="removeQuestionOption(index)">删除</el-button></div><el-button v-if="questionForm.questionType!=='判断'" link type="primary" @click="addQuestionOption">+ 添加选项</el-button></div></el-form-item><el-form-item required label="正确答案"><el-select v-if="questionForm.questionType==='多选'" v-model="questionForm.answerValues" multiple placeholder="请选择全部正确选项"><el-option v-for="o in answerOptions()" :key="o.value" :label="o.label" :value="o.value"/></el-select><el-select v-else v-model="questionForm.answerValues" placeholder="请选择正确答案"><el-option v-for="o in answerOptions()" :key="o.value" :label="o.label" :value="o.value"/></el-select></el-form-item><el-form-item label="答案解析"><el-input v-model="questionForm.analysis" type="textarea" :rows="2"/></el-form-item></el-form><template #footer><el-button @click="questionDialog=false">取消</el-button><el-button type="primary" @click="saveQuestion">保存到题库</el-button></template></el-dialog>
<el-dialog v-model="ledgerDialog" title="录入线下安全教育台账" width="720"><el-form label-position="top"><div class="form-grid"><el-form-item required label="受教育人员"><el-select v-model="ledgerForm.workerId"><el-option v-for="w in projectWorkers" :key="w.id" :label="`${w.name}（${w.personCode}）`" :value="w.id"/></el-select></el-form-item><el-form-item required label="教育类型"><el-select v-model="ledgerForm.educationType"><el-option v-for="s in ['入场安全教育','三级安全教育','专项安全教育','班前教育','临时教育','其他']" :key="s" :label="s" :value="s"/></el-select></el-form-item><el-form-item required label="课程名称"><el-input v-model="ledgerForm.courseName"/></el-form-item><el-form-item required label="授课人"><el-input v-model="ledgerForm.teacher"/></el-form-item><el-form-item required label="教育日期"><el-date-picker v-model="ledgerForm.educationDate" value-format="YYYY-MM-DD"/></el-form-item><el-form-item required label="教育地点"><el-input v-model="ledgerForm.educationLocation"/></el-form-item><el-form-item required label="有效期开始"><el-date-picker v-model="ledgerForm.validStartDate" value-format="YYYY-MM-DD"/></el-form-item><el-form-item required label="有效期结束"><el-date-picker v-model="ledgerForm.validEndDate" value-format="YYYY-MM-DD"/></el-form-item><el-form-item required label="是否通过"><el-switch v-model="ledgerForm.passed" active-text="通过" inactive-text="未通过"/></el-form-item><el-form-item required label="学时"><el-input-number v-model="ledgerForm.classHours" :min="0"/></el-form-item></div></el-form><template #footer><el-button @click="ledgerDialog=false">取消</el-button><el-button type="primary" @click="saveLedger">保存台账</el-button></template></el-dialog>
<el-dialog v-model="permissionDialog" title="配置人员区域权限" width="680"><el-form label-position="top"><el-form-item required label="劳务人员"><el-select v-model="permissionForm.workerId" filterable><el-option v-for="w in projectWorkers" :key="w.id" :label="`${w.name}（${w.personCode}）`" :value="w.id"/></el-select></el-form-item><el-form-item required label="允许进入区域"><el-checkbox-group v-model="permissionForm.areaIds" class="area-checks"><el-checkbox v-for="a in projectAreas" :key="a.id" :value="a.id" :label="a.id">{{a.areaName}}（{{a.areaType}}）</el-checkbox></el-checkbox-group></el-form-item><div class="form-grid"><el-form-item required label="有效期开始"><el-date-picker v-model="permissionForm.validStartTime" type="datetime" value-format="YYYY-MM-DDTHH:mm:ss"/></el-form-item><el-form-item required label="有效期结束"><el-date-picker v-model="permissionForm.validEndTime" type="datetime" value-format="YYYY-MM-DDTHH:mm:ss"/></el-form-item></div><el-alert title="保存区域权限后，需要人员在场且安全教育已通过，才能下发到对应区域的设备。" type="info" :closable="false"/></el-form><template #footer><el-button @click="permissionDialog=false">取消</el-button><el-button type="primary" @click="savePermission">保存区域权限</el-button></template></el-dialog>
<el-dialog v-model="trainingTaskDialog" :title="editingTrainingTask?'编辑培训任务':'新增培训任务'" width="720"><el-alert title="培训任务可以覆盖全项目人员，也可以只指定部分班组或人员。" type="info" :closable="false"/><el-form label-position="top"><div class="form-grid"><el-form-item required label="任务名称"><el-input v-model="trainingTaskForm.name"/></el-form-item><el-form-item required label="培训课程"><el-select v-model="trainingTaskForm.courseId"><el-option v-for="c in educationCourses" :key="c.id" :label="c.name" :value="c.id"/></el-select></el-form-item><el-form-item required label="培训对象范围"><el-select v-model="trainingTaskForm.targetType" @change="trainingTaskForm.targetIds=[]"><el-option label="全项目人员" value="ALL"/><el-option label="指定班组" value="TEAM"/><el-option label="指定人员" value="WORKER"/></el-select></el-form-item><el-form-item v-if="trainingTaskForm.targetType==='TEAM'" required label="指定班组"><el-select v-model="trainingTaskForm.targetIds" multiple collapse-tags><el-option v-for="t in projectTeams" :key="t.id" :label="t.teamName" :value="t.id"/></el-select></el-form-item><el-form-item v-if="trainingTaskForm.targetType==='WORKER'" required label="指定人员"><el-select v-model="trainingTaskForm.targetIds" multiple collapse-tags filterable><el-option v-for="w in projectWorkers" :key="w.id" :label="`${w.name}（${w.personCode}）`" :value="w.id"/></el-select></el-form-item><el-form-item required label="开始时间"><el-date-picker v-model="trainingTaskForm.startTime" type="datetime" value-format="YYYY-MM-DDTHH:mm:ss"/></el-form-item><el-form-item required label="结束时间"><el-date-picker v-model="trainingTaskForm.endTime" type="datetime" value-format="YYYY-MM-DDTHH:mm:ss"/></el-form-item><el-form-item required label="状态"><el-select v-model="trainingTaskForm.status"><el-option label="开放" value="ACTIVE"/><el-option label="停用" value="DISABLED"/></el-select></el-form-item></div><el-form-item label="备注"><el-input v-model="trainingTaskForm.remark"/></el-form-item></el-form><template #footer><el-button @click="trainingTaskDialog=fals