<el-dialog v-model="deviceDialog" :title="editingDevice?'编辑考勤设备':'新增考勤设备'" width="720"><el-alert title="设备直接绑定项目区域。人员获得该区域权限后，才会被下发到这台设备。" type="info" :closable="false"/><el-form label-position="top"><div class="form-grid"><el-form-item required label="设备名称"><el-input v-model="deviceForm.deviceName"/></el-form-item><el-form-item required label="设备编号"><el-input v-model="deviceForm.deviceNo"/></el-form-item><el-form-item required label="绑定区域"><el-select v-model="deviceForm.areaId" clearable><el-option v-for="a in projectAreas" :key="a.id" :label="`${a.areaName}（${a.areaType}）`" :value="a.id"/></el-select></el-form-item><el-form-item required label="设备品牌"><el-select v-model="deviceForm.brand"><el-option label="宇泛" value="宇泛"/><el-option label="其他" value="其他"/></el-select></el-form-item><el-form-item label="设备型号"><el-input v-model="deviceForm.model"/></el-form-item><el-form-item required label="设备类型"><el-select v-model="deviceForm.deviceType"><el-option label="人脸考勤机" value="人脸考勤机"/><el-option label="闸机" value="闸机"/><el-option label="门禁" value="门禁"/></el-select></el-form-item><el-form-item required label="安装位置"><el-input v-model="deviceForm.location"/></el-form-item><el-form-item label="设备 IP"><el-input v-model="deviceForm.ipAddress"/></el-form-item><el-form-item required label="状态"><el-select v-model="deviceForm.status"><el-option label="在线" value="ONLINE"/><el-option label="离线" value="OFFLINE"/><el-option label="未知" value="UNKNOWN"/></el-select></el-form-item></div></el-form><template #footer><el-button @click="deviceDialog=false">取消</el-button><el-button type="primary" @click="saveDevice">保存设备</el-button></template></el-dialog>
<el-dialog v-model="qrDialog" title="培训任务二维码" width="520" class="qr-dialog"><div class="qr-content"><img :src="qrDataUrl" alt="培训任务二维码"/><p>{{qrUrl}}</p><el-alert v-if="qrLocalOnly" title="当前通过 localhost 打开系统，二维码只能在本机使用。手机扫码时，请通过本机局域网 IP 打开后台后重新生成二维码，或等待部署到服务器。" type="warning" :closable="false"/><el-alert v-else title="二维码已使用当前访问地址生成，手机与本机网络互通时可直接扫码考试。" type="success" :closable="false"/></div><template #footer><el-button @click="qrDialog=false">关闭</el-button></template></el-dialog>
